import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Upload } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminArtistForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [formData, setFormData] = useState({
    Artist_ID: '',
    Name_En: '',
    Name_Ar: '',
    Bio_En: '',
    Image: ''
  });

  useEffect(() => {
    if (id) {
      AdminService.getArtistById(id).then((res: any) => {
        setFormData(res.data);
      }).catch(() => toast.error("Entry not found"));
    }
  }, [id]);

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertArtist(formData);
      toast.success(id ? "Record Updated" : "New Artist Created");
      navigate('/admin/artists');
    } catch (err) {
      toast.error("Process Failed");
    } finally {
      setLoading(false);
    }
  };

  const handleExcelImport = async () => {
    if (!file) return toast.error("Select file first");
    setLoading(true);
    try {
      await AdminService.importData('artist', file);
      toast.success("Excel Sync Complete");
      navigate('/admin/artists');
    } catch (err) {
      toast.error("Import Failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-6xl mx-auto p-8 space-y-10 animate-in fade-in duration-700">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-400 font-black text-[10px] uppercase hover:text-primary transition-colors">
        <ArrowLeft size={14} /> Return
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 bg-white dark:bg-[#0f0f0f] p-10 rounded-[3rem] border border-gray-100 dark:border-white/5 shadow-2xl">
          <h2 className="text-3xl font-black italic uppercase mb-8">{id ? 'Edit' : 'Manual'} <span className="text-primary">Artist</span></h2>
          <form onSubmit={handleManualSubmit} className="grid grid-cols-2 gap-6">
            <div className="col-span-1 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">Unique ID</label>
              <input value={formData.Artist_ID} onChange={e => setFormData({...formData, Artist_ID: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 border-transparent p-4 rounded-2xl outline-none focus:ring-2 focus:ring-primary dark:text-white font-bold" placeholder="AR-XX" required disabled={!!id} />
            </div>
            <div className="col-span-1 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">Name (English)</label>
              <input value={formData.Name_En} onChange={e => setFormData({...formData, Name_En: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl outline-none focus:ring-2 focus:ring-primary dark:text-white font-bold" required />
            </div>
            <div className="col-span-2 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">Bio (English)</label>
              <textarea value={formData.Bio_En} onChange={e => setFormData({...formData, Bio_En: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl h-40 outline-none focus:ring-2 focus:ring-primary dark:text-white font-bold" />
            </div>
            <button type="submit" disabled={loading} className="col-span-2 bg-black text-white py-5 rounded-2xl font-black uppercase tracking-[0.2em] text-[10px] hover:bg-primary transition-all flex items-center justify-center gap-3">
              <Save size={16} /> {id ? 'Save Changes' : 'Create Record'}
            </button>
          </form>
        </div>

        {!id && (
          <div className="bg-white dark:bg-[#0f0f0f] p-8 rounded-[3rem] border border-gray-100 dark:border-white/5 h-fit text-center space-y-6">
            <h3 className="text-sm font-black uppercase italic">Excel <span className="text-primary">Import</span></h3>
            <div className="border-2 border-dashed border-gray-100 dark:border-white/10 rounded-2xl p-8 relative group">
              <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => setFile(e.target.files?.[0] || null)} />
              <Upload className="mx-auto text-gray-300 group-hover:text-primary mb-2" size={32} />
              <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest">{file ? file.name : 'Click to Upload'}</p>
            </div>
            <button onClick={handleExcelImport} disabled={loading} className="w-full bg-gray-50 dark:bg-white/5 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-black hover:text-white transition-all">Start Import</button>
          </div>
        )}
      </div>
    </div>
  );
};
